/*
 * Process Synchronization: Producer-Consumer Problem
 * Using POSIX Threads, Mutexes, and Semaphores
 * 
 * Compile: gcc -pthread -o prod_cons prod_cons.c
 * Run: ./prod_cons
 */

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <semaphore.h>
#include <unistd.h>
#include <time.h>

/* Buffer configuration */
#define BUFFER_SIZE 5
#define NUM_ITEMS 10

/* Shared buffer and tracking variables */
int buffer[BUFFER_SIZE];
int in = 0; /* Producer writes at this index */
int out = 0; /* Consumer reads from this index */
int count = 0; /* Number of items in buffer */

/* Synchronization primitives */
pthread_mutex_t mutex; /* Binary semaphore for mutual exclusion */
sem_t empty; /* Counting semaphore - empty slots */
sem_t full; /* Counting semaphore - filled slots */

/* For displaying buffer state */
void print_buffer() {
 printf("Buffer [ ");
 for (int i = 0; i < BUFFER_SIZE; i++) {
 if (buffer[i] == -1)
 printf("_ ");
 else
 printf("%d ", buffer[i]);
 }
 printf("] in=%d out=%d count=%d\n", in, out, count);
}

/* Producer thread function */
void* producer(void* arg) {
 int producer_id = *(int*)arg;

 for (int i = 0; i < NUM_ITEMS; i++) {
 int item = (producer_id * 100) + i + 1; /* Produce unique item */

 /* ENTRY SECTION: Wait for empty slot */
 sem_wait(&empty); /* P(empty) - decrement empty count */

 /* CRITICAL SECTION: Enter mutex */
 pthread_mutex_lock(&mutex);

 /* Add item to buffer */
 buffer[in] = item;
 count++;
 printf("Producer %d: Produced item %d at position %d. ", 
 producer_id, item, in);
 print_buffer();

 /* Update circular buffer index */
 in = (in + 1) % BUFFER_SIZE;

 /* EXIT SECTION: Signal mutex and full */
 pthread_mutex_unlock(&mutex);
 sem_post(&full); /* V(full) - increment full count */

 /* Random delay to simulate work */
 usleep(rand() % 500000); /* 0-500ms */
 }

 return NULL;
}

/* Consumer thread function */
void* consumer(void* arg) {
 int consumer_id = *(int*)arg;

 for (int i = 0; i < NUM_ITEMS; i++) {
 /* ENTRY SECTION: Wait for filled slot */
 sem_wait(&full); /* P(full) - wait for item */

 /* CRITICAL SECTION: Enter mutex */
 pthread_mutex_lock(&mutex);

 /* Remove item from buffer */
 int item = buffer[out];
 buffer[out] = -1; /* Mark as empty */
 count--;
 printf("Consumer %d: Consumed item %d from position %d. ", 
 consumer_id, item, out);
 print_buffer();

 /* Update circular buffer index */
 out = (out + 1) % BUFFER_SIZE;

 /* EXIT SECTION: Signal mutex and empty */
 pthread_mutex_unlock(&mutex);
 sem_post(&empty); /* V(empty) - free up slot */

 /* Random delay to simulate work */
 usleep(rand() % 500000); /* 0-500ms */
 }

 return NULL;
}

/* Demonstration of race condition (without synchronization) */
void demonstrate_race_condition() {
 printf("\n=== RACE CONDITION DEMONSTRATION ===\n");

 volatile int shared_counter = 0; /* volatile prevents optimization */
 int iterations = 100000;

 /* Function to increment without synchronization */
 void increment() {
 for (int i = 0; i < iterations; i++) {
 /* This is NOT atomic - three steps: load, increment, store */
 int temp = shared_counter;
 temp = temp + 1;
 shared_counter = temp;
 }
 }

 /* Function to decrement without synchronization */
 void decrement() {
 for (int i = 0; i < iterations; i++) {
 int temp = shared_counter;
 temp = temp - 1;
 shared_counter = temp;
 }
 }

 pthread_t t1, t2;

 shared_counter = 0;
 pthread_create(&t1, NULL, (void*(*)(void*))increment, NULL);
 pthread_create(&t2, NULL, (void*(*)(void*))decrement, NULL);
 pthread_join(t1, NULL);
 pthread_join(t2, NULL);

 printf("Without synchronization:\n");
 printf(" Expected: 0\n");
 printf(" Actual: %d\n", shared_counter);
 printf(" Lost updates: %d\n\n", abs(shared_counter));
}

int main() {
 /* Seed random number generator */
 srand(time(NULL));

 /* Initialize synchronization primitives */
 pthread_mutex_init(&mutex, NULL);
 sem_init(&empty, 0, BUFFER_SIZE); /* All slots initially empty */
 sem_init(&full, 0, 0); /* No slots initially full */

 /* Initialize buffer */
 for (int i = 0; i < BUFFER_SIZE; i++) {
 buffer[i] = -1; /* -1 indicates empty slot */
 }

 /* Demonstrate race condition */
 demonstrate_race_condition();

 /* Create producer and consumer threads */
 printf("\n=== PRODUCER-CONSUMER WITH SEMAPHORES ===\n");

 pthread_t prod1, prod2, cons1, cons2;
 int id1 = 1, id2 = 2;

 /* Create 2 producers and 2 consumers */
 pthread_create(&prod1, NULL, producer, &id1);
 pthread_create(&prod2, NULL, producer, &id2);
 pthread_create(&cons1, NULL, consumer, &id1);
 pthread_create(&cons2, NULL, consumer, &id2);

 /* Wait for all threads to complete */
 pthread_join(prod1, NULL);
 pthread_join(prod2, NULL);
 pthread_join(cons1, NULL);
 pthread_join(cons2, NULL);

 printf("\n=== ALL OPERATIONS COMPLETED ===\n");
 printf("Final buffer count: %d (should be 0)\n", count);

 /* Clean up */
 pthread_mutex_destroy(&mutex);
 sem_destroy(&empty);
 sem_destroy(&full);

 return 0;
}

/*
 * Process Synchronization in Java
 * Demonstrates: Custom Semaphore, Mutex, Producer-Consumer
 * university 2022 Scheme - Operating Systems Lab
 */

import java.util.LinkedList;
import java.util.Queue;
import java.util.concurrent.locks.Condition;
import java.util.concurrent.locks.ReentrantLock;

/**
 * Custom Semaphore Implementation
 * Demonstrates the core WAIT (P) and SIGNAL (V) operations
 */
class CustomSemaphore {
 private int value; // Current value of semaphore
 private final String name;
 private final Queue<Thread> waitQueue = new LinkedList<>();

 public CustomSemaphore(int initialValue, String name) {
 this.value = initialValue;
 this.name = name;
 }

 /**
 * P operation (wait/decrement)
 * If value < 0, the process blocks and waits
 */
 public synchronized void waitOperation() throws InterruptedException {
 value--;
 if (value < 0) {
 waitQueue.add(Thread.currentThread());
 System.out.println(Thread.currentThread().getName() + 
 " blocked on semaphore '" + name + "' (value=" + value + ")");
 wait(); // Block the thread
 }
 }

 /**
 * V operation (signal/increment)
 * Wakes up a waiting process if any
 */
 public synchronized void signalOperation() {
 value++;
 if (value <= 0) {
 Thread waitingThread = waitQueue.poll();
 if (waitingThread != null) {
 System.out.println(waitingThread.getName() + 
 " awakened on semaphore '" + name + "'");
 waitingThread.notify(); // Wake up one waiting thread
 }
 }
 }

 public int getValue() {
 return value;
 }
}

/**
 * Bounded Buffer for Producer-Consumer Problem
 * Uses counting semaphores for synchronization
 */
class BoundedBuffer<T> {
 private final int capacity;
 private final Queue<T> buffer;

 // Synchronization primitives
 private final ReentrantLock mutex = new ReentrantLock(); // Binary semaphore
 private final CustomSemaphore empty; // Counting semaphore for empty slots
 private final CustomSemaphore full; // Counting semaphore for filled slots

 public BoundedBuffer(int capacity) {
 this.capacity = capacity;
 this.buffer = new LinkedList<>();
 this.empty = new CustomSemaphore(capacity, "empty");
 this.full = new CustomSemaphore(0, "full");
 }

 /**
 * Producer: Add item to buffer
 */
 public void put(T item) throws InterruptedException {
 // P(empty) - wait for empty slot
 empty.waitOperation();

 // Enter critical section
 mutex.lock();
 try {
 buffer.add(item);
 System.out.println("Producer produced: " + item + 
 " | Buffer size: " + buffer.size());

 // Visual representation of buffer
 System.out.print(" Buffer: [ ");
 for (T element : buffer) {
 System.out.print(element + " ");
 }
 for (int i = buffer.size(); i < capacity; i++) {
 System.out.print("_ ");
 }
 System.out.println("]");
 } finally {
 mutex.unlock();
 }

 // V(full) - signal that item is available
 full.signalOperation();
 }

 /**
 * Consumer: Remove item from buffer
 */
 public T get() throws InterruptedException {
 // P(full) - wait for item to be available
 full.waitOperation();

 // Enter critical section
 mutex.lock();
 T item;
 try {
 item = buffer.remove();
 System.out.println("Consumer consumed: " + item + 
 " | Buffer size: " + buffer.size());
 } finally {
 mutex.unlock();
 }

 // V(empty) - signal that slot is available
 empty.signalOperation();

 return item;
 }
}

/**
 * Demonstration of Race Condition
 */
class RaceConditionDemo {
 private int sharedCounter = 0;
 private final int ITERATIONS = 100000;

 /**
 * Increment without synchronization - causes race condition
 */
 public void incrementUnsafe() {
 for (int i = 0; i < ITERATIONS; i++) {
 // Three-step non-atomic operation
 int temp = sharedCounter;
 temp = temp + 1;
 sharedCounter = temp;
 }
 }

 /**
 * Decrement without synchronization - causes race condition
 */
 public void decrementUnsafe() {
 for (int i = 0; i < ITERATIONS; i++) {
 int temp = sharedCounter;
 temp = temp - 1;
 sharedCounter = temp;
 }
 }

 /**
 * Increment with proper synchronization
 */
 private final ReentrantLock lock = new ReentrantLock();

 public void incrementSafe() {
 lock.lock();
 try {
 sharedCounter++;
 } finally {
 lock.unlock();
 }
 }

 public void decrementSafe() {
 lock.lock();
 try {
 sharedCounter--;
 } finally {
 lock.unlock();
 }
 }

 public int getCounter() {
 return sharedCounter;
 }

 public void reset() {
 sharedCounter = 0;
 }
}

/**
 * Main class to demonstrate all synchronization concepts
 */
public class ProcessSynchronization {

 public static void main(String[] args) throws InterruptedException {
 System.out.println("=" .repeat(60));
 System.out.println("Process Synchronization - Java Implementation");
 System.out.println("=" .repeat(60));

 // Part 1: Race Condition Demonstration
 System.out.println("\n--- PART 1: Race Condition Demonstration ---\n");
 demonstrateRaceCondition();

 // Part 2: Producer-Consumer with Custom Semaphores
 System.out.println("\n--- PART 2: Producer-Consumer Problem ---\n");
 demonstrateProducerConsumer();
 }

 private static void demonstrateRaceCondition() throws InterruptedException {
 RaceConditionDemo demo = new RaceConditionDemo();

 // Test 1: Without synchronization
 System.out.println("Test 1: WITHOUT synchronization");
 Thread t1 = new Thread(() -> demo.incrementUnsafe(), "Incrementer");
 Thread t2 = new Thread(() -> demo.decrementUnsafe(), "Decrementer");

 t1.start();
 t2.start();
 t1.join();
 t2.join();

 System.out.println(" Expected: 0");
 System.out.println(" Actual: " + demo.getCounter());
 System.out.println(" Lost updates: " + Math.abs(demo.getCounter()));

 // Test 2: With synchronization
 System.out.println("\nTest 2: WITH synchronization (Mutex)");
 demo.reset();

 Thread t3 = new Thread(() -> {
 for (int i = 0; i < demo.getClass().getDeclaredField("ITERATIONS").getInt(null); i++) {
 demo.incrementSafe();
 }
 }, "SafeIncrementer");

 Thread t4 = new Thread(() -> {
 for (int i = 0; i < 100000; i++) {
 demo.decrementSafe();
 }
 }, "SafeDecrementer");

 t3.start();
 t4.start();
 t3.join();
 t4.join();

 System.out.println(" Expected: 0");
 System.out.println(" Actual: " + demo.getCounter());
 System.out.println(" Result: " + (demo.getCounter() == 0 ? "CORRECT" : "INCORRECT"));
 }

 private static void demonstrateProducerConsumer() throws InterruptedException {
 BoundedBuffer<Integer> buffer = new BoundedBuffer<>(5);

 // Producer threads
 Thread producer1 = new Thread(() -> {
 try {
 for (int i = 1; i <= 5; i++) {
 buffer.put(i);
 Thread.sleep(100);
 }
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }, "Producer-1");

 // Consumer threads
 Thread consumer1 = new Thread(() -> {
 try {
 for (int i = 1; i <= 5; i++) {
 buffer.get();
 Thread.sleep(150);
 }
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }, "Consumer-1");

 producer1.start();
 consumer1.start();

 producer1.join();
 consumer1.join();

 System.out.println("\nProducer-Consumer execution completed!");
 }
}

/*
 * Key Concepts Demonstrated:
 * 
 * 1. CUSTOM SEMAPHORE:
 * - waitOperation() - P operation (proberen/test)
 * - signalOperation() - V operation (verhogen/increment)
 * - Uses object monitors (wait/notify) for blocking
 * 
 * 2. MUTUAL EXCLUSION:
 * - ReentrantLock provides binary semaphore functionality
 * - Ensures only one thread enters critical section
 * 
 * 3. PRODUCER-CONSUMER:
 * - Empty semaphore counts available slots
 * - Full semaphore counts filled slots
 * - Mutex protects buffer access
 * 
 * 4. RACE CONDITION:
 * - Demonstrates interleaving of non-atomic operations
 * - Shows how synchronization fixes data inconsistency
 */
